/* 一级标题样式 */
h1 {
}
.h1_content::before {
}
.h1_content::after {
}
h1_prefix {
}
h1_content {
  clear: both;
  border-bottom: none;
    font-size: 32px;
      font-weight: 900;
      letter-spacing: 3px;
  box-shadow: none;
      background: linear-gradient(90deg, red, orange, yellow, green, cyan, blue, purple);
      background-size: 600% 600%;
      -webkit-background-clip: text;
      background-clip: text;
      color: transparent;
      animation: rainbowMove 3s linear infinite;
}
@keyframes rainbowMove {
      0% { background-position: 0% 50%; }
      100% { background-position: 100% 50%; }
    }
h1_suffix {
}
/* 二级标题样式 */
h2 {
}
h2_prefix {
}
.h2_content::before {
    }
.h2_content::after {
    }
h2_content {
 font-size: 24px;
  font-weight: 700;
  background: linear-gradient(90deg,#000000,orange,#000000);
  background-size: 180% 100%;
  -webkit-background-clip: text;
  color: transparent;
  text-shadow: 0 0 22px #66bbff;
  animation: h2In 0.9s ease-out forwards, h2Loop 3s ease infinite alternate;
}
@keyframes h2In {
  0% {transform: translateX(-150px);opacity:0;filter: blur(6px);}
  100% {transform: translateX(0);opacity:1;filter: blur(0);}
}
@keyframes h2Loop {
  0% {background-position: 0;transform: translateY(0);}
  100% {background-position: 180%;transform: translateY(-6px);}
}
h2_suffix {
}
/* 三级标题样式 */
h3 {
}
h3_prefix {
}
h3_content {
  clear: both;
  display:block;
  font-size: 18px;
  font-weight: 600;
  margin: auto;
  text-align: center;
  color: #0000ff;
  text-shadow: 0 0 14px #00e0bb;
  animation: h3In 0.75s ease-out forwards, h3Loop 2.5s infinite alternate;
  border-bottom: none;
  border-left: none;
}
@keyframes h3In {
  0% {transform: translateY(50px);opacity:0;}
  100% {transform: translateY(0);opacity:1;}
}
@keyframes h3Loop {
  0% {text-shadow:0 0 8px #00e0bb;}
  100% {text-shadow:0 0 20px #00ffdd;}
}
h3_suffix {
}
/* 四级标题样式 */
h4 {
}
h4_prefix {
}
h4_content {
  font-size: 16px;
  font-weight: 500;
  margin: auto;
  text-align: center;
  color: #fff;
  -webkit-text-stroke:1px #ee99ff;
  text-shadow: 0 0 8px #aa77ff;
  animation: h4In 0.6s forwards, h4Loop 4s infinite alternate;
}
@keyframes h4In {
  0% {opacity:0;filter: blur(4px);}
  100% {opacity:1;filter: blur(0);}
}
@keyframes h4Loop {
  0% {opacity:0.85;}
  100% {opacity:1;}
}
h4_suffix {
}
/* 五级标题样式 */
h5 {
}
h5_prefix {
}
h5_content {
  font-size: 16px;
  font-weight: 400;
  margin: auto;
  text-align: center;
  color: #0000ff;
  animation: h5In 0.45s forwards;
}
@keyframes h5In {
  0% {opacity:0;letter-spacing: -5px;}
  100% {opacity:1;letter-spacing: 0;}
}
h5_suffix {
}
/* 六级标题样式 */
